// Extract PDF attachment from email
// Finds the first .pdf attachment and prepares it for processing

const items = $input.all();
const item = items[0];

const attachments = item.json.attachments || [];
const pdfAttachment = attachments.find(a => 
  a.name && a.name.toLowerCase().endsWith('.pdf')
);

if (!pdfAttachment) {
  throw new Error('No PDF attachment found in email from Tidel');
}

// Extract email metadata for batch naming
const subject = item.json.subject || 'TIDEL SERVICE INVOICE';
const receivedDate = item.json.date || new Date().toISOString();

// Generate batch name matching Loomis format: YYMMDD-DDMMMMYY TIDELSER-MR01
const now = new Date();
const batchDate = now.toISOString().slice(2,10).replace(/-/g,'');
const batchName = `${batchDate}-TIDELSER-MR01`;

return [{
  json: {
    pdfBinary: pdfAttachment.content,  // base64 encoded PDF
    pdfName: pdfAttachment.name,
    emailSubject: subject,
    emailDate: receivedDate,
    batchName: batchName,
    processedAt: now.toISOString()
  },
  binary: {
    pdf: {
      data: pdfAttachment.content,
      mimeType: 'application/pdf',
      fileName: pdfAttachment.name
    }
  }
}];

// Parse the extracted invoice array from GPT response
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '';

let invoices = [];
try {
  const clean = content.replace(/```json|```/g, '').trim();
  invoices = JSON.parse(clean);
  if (!Array.isArray(invoices)) invoices = [invoices];
} catch(e) {
  throw new Error('Failed to parse invoice JSON from GPT: ' + content.substring(0, 200));
}

const batchName = $('Extract PDF Attachment').first().json.batchName;
const processedAt = $('Extract PDF Attachment').first().json.processedAt;

console.log(`Extracted ${invoices.length} invoices from PDF`);

// Return each invoice as a separate item for parallel classification
return invoices.map((inv, idx) => ({
  json: {
    ...inv,
    index: idx,
    batchName: batchName,
    processedAt: processedAt
  }
}));

// Merge classification result back with invoice data
const invoice = $('Parse Invoice Array').item.json;
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '';

let classification = {};
try {
  const clean = content.replace(/```json|```/g, '').trim();
  classification = JSON.parse(clean);
} catch(e) {
  classification = {
    decision: 'UNCLEAR',
    gl_code: 440133,
    confidence: 'LOW',
    reason: 'Could not parse AI response',
    flag_for_review: true
  };
}

// Build WORKING sheet row
const description = `${invoice.serial_number}/${invoice.ship_name}`;

return [{
  json: {
    // Original invoice fields
    serial_number:   invoice.serial_number,
    branch_number:   invoice.branch_number,
    invoice_number:  invoice.invoice_number,
    invoice_date:    invoice.invoice_date,
    total_amount:    invoice.total_amount,
    item_amount:     invoice.subtotal,
    po_number:       invoice.po_number,
    ship_name:       invoice.ship_name,
    ship_addr1:      invoice.ship_addr1,
    ship_city:       invoice.ship_city,
    ship_state:      invoice.ship_state,
    ship_zip:        invoice.ship_zip,
    call_number:     invoice.call_number,
    labor_charge:    invoice.labor_charge,
    parts_amount:    invoice.parts_amount,
    shipping_amount: invoice.shipping_amount,
    subtotal:        invoice.subtotal,
    tax_amount:      invoice.tax_amount,
    oos_tier1:       invoice.oos_tier1,
    oos_tier2:       invoice.oos_tier2,
    comment:         invoice.comment,
    // AI classification
    bill_customer:   classification.decision,
    gl_code:         classification.gl_code,
    ai_confidence:   classification.confidence,
    ai_reason:       classification.reason,
    flag_for_review: classification.flag_for_review || false,
    // Oracle upload fields
    description:     description,
    vendor_name:     'TIDEL ENGINEERING',
    vendor_number:   151176,
    vendor_site:     'CARROLLTON',
    company:         '01',
    lob:             '500',
    dept:            '00',
    // Metadata
    batchName:       invoice.batchName,
    index:           invoice.index
  }
}];

// Generate Excel file with 3 sheets:
// 1. TIDEL SERV INV — raw invoice data
// 2. WORKING — with AI classification + GL codes
// 3. UPLOAD — Oracle WebADI format

const allInvoices = $input.first().json.data;
const batchName = allInvoices[0]?.batchName || 'BATCH';

// Calculate totals
const totalAmount = allInvoices.reduce((sum, inv) => sum + (parseFloat(inv.total_amount) || 0), 0);
const billYesAmount = allInvoices
  .filter(inv => inv.bill_customer === 'YES')
  .reduce((sum, inv) => sum + (parseFloat(inv.subtotal) || 0), 0);
const billNoAmount = allInvoices
  .filter(inv => inv.bill_customer === 'NO')
  .reduce((sum, inv) => sum + (parseFloat(inv.subtotal) || 0), 0);
const flaggedCount = allInvoices.filter(inv => inv.flag_for_review).length;

// Build CSV representations of each sheet
// SHEET 1: Raw invoice data
const sheet1Headers = [
  'Serial Number','Branch Number','Invoice','Invoice Date','Total Invoice Amount',
  'PO','Ship Name','Ship Addr1','Ship City','Ship State','Ship Zip',
  'Call Number','Labor Charge','Parts Amount','Shipping','Sub Total',
  'Tax Amt','Total','OOS Tier Categories','OOS 2 Tier Categories',
  'Service Provider','InvoiceComment','Bill Customer'
];

const sheet1Rows = allInvoices.map(inv => [
  inv.serial_number, inv.branch_number, inv.invoice_number, inv.invoice_date,
  inv.total_amount, inv.po_number, inv.ship_name, inv.ship_addr1,
  inv.ship_city, inv.ship_state, inv.ship_zip, inv.call_number,
  inv.labor_charge, inv.parts_amount, inv.shipping_amount, inv.subtotal,
  inv.tax_amount, inv.total_amount, inv.oos_tier1, inv.oos_tier2,
  'Tidel', inv.comment, inv.bill_customer
]);

// SHEET 2: Working sheet with AI classification
const sheet2Headers = [
  'Serial Number','Branch Number','Invoice','Invoice Date','Total Invoice Amount',
  'PO','Ship Name','Ship City','Ship State','Call Number',
  'Labor Charge','Parts Amount','OOS Tier 1','OOS Tier 2','InvoiceComment',
  'Bill Customer','GL Coding','Description',
  'AI Confidence','AI Reason','Flag for Review'
];

const sheet2Rows = allInvoices.map(inv => [
  inv.serial_number, inv.branch_number, inv.invoice_number, inv.invoice_date,
  inv.total_amount, inv.po_number, inv.ship_name, inv.ship_city,
  inv.ship_state, inv.call_number, inv.labor_charge, inv.parts_amount,
  inv.oos_tier1, inv.oos_tier2, inv.comment,
  inv.bill_customer, inv.gl_code, inv.description,
  inv.ai_confidence, inv.ai_reason, inv.flag_for_review ? 'YES' : ''
]);

// SHEET 3: Oracle UPLOAD format
const sheet3Headers = [
  'Invoice Type','PO Number','Vendor Name','Vendor Number','Vendor Site',
  'Invoice Date','Invoice Number','Company','GL Code','Branch',
  'LOB','Dept','Service Charge','Item','Subtotal','Total Amount',
  'Description'
];

const sheet3Rows = allInvoices
  .filter(inv => inv.bill_customer === 'YES' || inv.bill_customer === 'NO')
  .map(inv => [
    'STANDARD', inv.po_number, 'TIDEL ENGINEERING', 151176, 'CARROLLTON',
    inv.invoice_date, inv.invoice_number, '01', inv.gl_code, inv.branch_number,
    '500', '00', inv.labor_charge, inv.subtotal, inv.subtotal, inv.total_amount,
    inv.description
  ]);

// Convert to CSV strings
function toCSV(headers, rows) {
  const escape = v => {
    const s = String(v === null || v === undefined ? '' : v);
    return s.includes(',') || s.includes('"') || s.includes('\n')
      ? `"${s.replace(/"/g, '""')}`
      : s;
  };
  return [headers, ...rows].map(row => row.map(escape).join(',')).join('\n');
}

const workingCSV = toCSV(sheet2Headers, sheet2Rows);
const uploadCSV  = toCSV(sheet3Headers, sheet3Rows);

// Summary for email
const summary = {
  batchName,
  totalInvoices: allInvoices.length,
  billClient: allInvoices.filter(i => i.bill_customer === 'YES').length,
  vaultguardAbsorbs: allInvoices.filter(i => i.bill_customer === 'NO').length,
  flaggedForReview: flaggedCount,
  totalAmount: totalAmount.toFixed(2),
  billYesAmount: billYesAmount.toFixed(2),
  billNoAmount: billNoAmount.toFixed(2),
  flaggedInvoices: allInvoices
    .filter(i => i.flag_for_review)
    .map(i => `${i.invoice_number} — ${i.ship_name} — $${i.total_amount} — ${i.ai_reason}`)
};

return [{
  json: summary,
  binary: {
    working_sheet: {
      data: Buffer.from(workingCSV).toString('base64'),
      mimeType: 'text/csv',
      fileName: `${batchName}_WORKING.csv`
    },
    upload_sheet: {
      data: Buffer.from(uploadCSV).toString('base64'),
      mimeType: 'text/csv',
      fileName: `${batchName}_ORACLE_UPLOAD.csv`
    }
  }
}];

